arguments.content:
.forklift--learning {
  .forklift--learning {
    &__header {
      .pf-v6-c-menu-toggle {
        --pf-v6-c-menu-toggle--BackgroundColor: var(--pf-t--global--BackgroundColor--light-100);

        .pf-v6-theme-dark & {
          --pf-v6-c-menu-toggle--BackgroundColor: var(--pf-t--global--background--color--inverse--default);

        }
      }
    }

    &__help-section {
      &.m-has-descriptions {
        .pf-v6-c-expandable-section__content {
          --pf-v6-c-expandable-section__content--MarginTop: 0;
        }
      }

      &.m-non-expandable {
        // expandable-section toggle sub-element classes were removed in PF v6;
        // apply overrides via the component's top-level class instead
        .pf-v6-c-expandable-section {
          cursor: default;

          color: var(--pf-t--global--text--color--regular);
        }
      }

      li {
        &:not(:last-child) {
          margin-bottom: var(--pf-t--global--spacer--300);
        }
      }
    }

    &__help-description {
      &:not(:last-of-type) {
        border-bottom: 1px solid var(--pf-t--global--border--color--default);
      }

      &:not(:first-of-type) {
        margin-top: var(--pf-t--global--spacer--300);
      }
    }

    &__list-type {
      &--circle {
        > ul, > ol {
          list-style: circle;
        }
      }

      &--disc {
        > ul, > ol {
          list-style: disc;
        }
      }

      &--square {
        > ul, > ol {
          list-style-type: square;
        }
      }

      &--lower-alpha {
        > ul, > ol {
          list-style: lower-alpha;
        }
      }

      &--decimal {
        > ul, > ol {
          list-style: decimal;
        }
      }

      &--none {
        > ul, > ol {
          > li::marker {
            color: transparent;
          }
        }
      }
    }
  }
}

